import{_ as t,o as r,c as a,a2 as l}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"通道与 Web 工作台","description":"","frontmatter":{},"headers":[],"relativePath":"product/channels-ui.md","filePath":"product/channels-ui.md","lastUpdated":1780517912000}'),o={name:"product/channels-ui.md"};function i(s,e,n,d,c,h){return r(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="通道与-web-工作台" tabindex="-1">通道与 Web 工作台 <a class="header-anchor" href="#通道与-web-工作台" aria-label="Permalink to &quot;通道与 Web 工作台&quot;">​</a></h1><h2 id="通道能力" tabindex="-1">通道能力 <a class="header-anchor" href="#通道能力" aria-label="Permalink to &quot;通道能力&quot;">​</a></h2><p>一个 Codex-to-IM 安装可以配置多个通道实例，例如多个飞书机器人。通道实例负责平台接入，聊天绑定负责某个群聊或单聊当前指向哪个 <code>BridgeSession</code>。</p><table tabindex="0"><thead><tr><th>能力</th><th>飞书</th></tr></thead><tbody><tr><td>普通文本收发</td><td>支持</td></tr><tr><td>多实例配置</td><td>支持</td></tr><tr><td>群聊绑定</td><td>支持</td></tr><tr><td>流式富卡片</td><td>支持</td></tr><tr><td>Rich card 表格/按钮/表单</td><td>支持</td></tr><tr><td>文件/图片发送</td><td>支持</td></tr><tr><td>新建/重命名群聊</td><td>支持</td></tr><tr><td>云文档聊天入口</td><td>支持</td></tr><tr><td><code>/require-at</code></td><td>支持</td></tr></tbody></table><p>通道能力不是写死在命令层，而是通过 <a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/contracts.ts" target="_blank" rel="noreferrer">BaseChannelAdapter</a> 的可选方法表达。命令层会优先使用平台能力，不支持时给出退化提示。</p><h2 id="飞书流式卡片和交互卡片" tabindex="-1">飞书流式卡片和交互卡片 <a class="header-anchor" href="#飞书流式卡片和交互卡片" aria-label="Permalink to &quot;飞书流式卡片和交互卡片&quot;">​</a></h2><p>飞书通道可以把模型输出渲染为流式卡片，并在卡片里展示状态、工具调用、任务进度和操作按钮。命令结果也可以使用 rich card、表格、表单和按钮。</p><p>设计模块：</p><ul><li>rich card 类型：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/domain/index.ts" target="_blank" rel="noreferrer">src/domain/index.ts</a></li><li>飞书 Markdown / CardKit 渲染：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/feishu/markdown.ts" target="_blank" rel="noreferrer">src/channels/feishu/markdown.ts</a></li><li>流式反馈控制：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/delivery/stream-feedback.ts" target="_blank" rel="noreferrer">src/channels/delivery/stream-feedback.ts</a></li><li>工具详情：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/shared/progress/tool-call-details.ts" target="_blank" rel="noreferrer">src/shared/progress/tool-call-details.ts</a></li><li>飞书 adapter：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/feishu/adapter.ts" target="_blank" rel="noreferrer">src/channels/feishu/adapter.ts</a></li></ul><h2 id="云文档聊天入口" tabindex="-1">云文档聊天入口 <a class="header-anchor" href="#云文档聊天入口" aria-label="Permalink to &quot;云文档聊天入口&quot;">​</a></h2><p>飞书通道可以接收云文档评论事件。默认模式是云文档评论回复：用户在云文档评论里 @ 机器人后，Bridge 会把评论内容作为输入交给当前 runtime，并把最终回复写回触发本轮输入的同一个云文档评论线程。默认模式建立后，同一文档后续评论可以作为这条云文档评论会话的后续消息处理，但仍通过评论线程交付。</p><p>云文档评论里 @ 机器人后发送 <code>/new [群名] [目录]</code> 会启用显式 doc-as-chat 模式。Bridge 会创建一个飞书群聊，把这份云文档映射到该群聊，并在群聊里继续承载普通 IM 会话。新模式建立后，云文档评论不再接入 bot 对话；如果用户继续在云文档评论里发消息，Bridge 只回复提示用户去已创建的群聊聊天。</p><p>未建立默认模式或新模式的云文档评论仍需要 @ 机器人，或由评论内容里的机器人 mention 触发，避免机器人订阅整个租户后误接收无关评论。机器人自己写出的云文档评论会被忽略，避免评论回复再次触发自身。</p><p>设计模块：</p><ul><li>云文档地址类型：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/domain/index.ts" target="_blank" rel="noreferrer">src/domain/index.ts</a></li><li>通道回复抽象：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/contracts.ts" target="_blank" rel="noreferrer">src/channels/contracts.ts</a></li><li>飞书评论事件和回复：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/feishu/adapter.ts" target="_blank" rel="noreferrer">src/channels/feishu/adapter.ts</a></li><li>交付管线：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/turn/delivery-pipeline.ts" target="_blank" rel="noreferrer">src/bridge/turn/delivery-pipeline.ts</a></li><li>飞书权限说明：<a href="./../guide/install-and-usage">docs/guide/install-and-usage.md</a></li></ul><h2 id="web-工作台" tabindex="-1">Web 工作台 <a class="header-anchor" href="#web-工作台" aria-label="Permalink to &quot;Web 工作台&quot;">​</a></h2><p>本地 Web 工作台默认运行在 <code>http://127.0.0.1:4781</code>，用于完成不适合在 IM 中操作的管理任务。</p><p>主要页面：</p><ul><li>概览：查看 UI、bridge、通道数量、配置目录和运行状态。</li><li>会话：查看 Bridge/IM 会话和本机 runtime 会话，进入历史详情，重命名或删除会话。</li><li>配置：编辑 Codex、Claude Code、Bridge 控制和 Web 访问设置。</li><li>通道：管理飞书实例、查看聊天绑定、切换默认目标。</li><li>日志：查看 bridge 日志。</li><li>命令说明：查看 IM 命令清单。</li></ul><p>设计模块：</p><ul><li>UI server：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/operator-ui/server.ts" target="_blank" rel="noreferrer">src/operator-ui/server.ts</a></li><li>UI 页面 shell：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/operator-ui/shell.ts" target="_blank" rel="noreferrer">src/operator-ui/shell.ts</a></li><li>UI auth：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/operator-ui/routes/auth.ts" target="_blank" rel="noreferrer">src/operator-ui/routes/auth.ts</a></li><li>UI session 应用层：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/operator-ui/application/session.ts" target="_blank" rel="noreferrer">src/operator-ui/application/session.ts</a></li><li>UI config 应用层：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/operator-ui/application/config.ts" target="_blank" rel="noreferrer">src/operator-ui/application/config.ts</a></li><li>UI channel 应用层：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/operator-ui/application/channel.ts" target="_blank" rel="noreferrer">src/operator-ui/application/channel.ts</a></li></ul>',21)])])}const u=t(o,[["render",i]]);export{p as __pageData,u as default};
